import React from "react";
import styled from "styled-components";
import Td from "smart-react-components/table/Td";
import Check from "../../components/icons/Check";
import Cross from "../../components/icons/Cross";
export default styled(Td).attrs(({ status }) => ({
    children: React.createElement("span", null, status ? React.createElement(Check, null) : React.createElement(Cross, null))
})) `
    > span {
        display: block;
        max-width: 150px;
        text-align: center;
    }
`;
